const REDUCER_TYPE = { SUBMIT: 'submit', DONE: 'done', ERROR: 'error' };
const reducer = (state, action) => { switch (action.type) { case REDUCER_TYPE.SUBMIT: return {status: 'submitting', error: null}; case REDUCER_TYPE.DONE: return {status: 'done', error: null}; case REDUCER_TYPE.ERROR: return {status: 'error', error: action.message}; default: return state; } };
function OrderForm() { const [items, setItems] = useState([...]); const [state, dispatch] = useReducer(reducer, { status: 'editing', error: null }); const totalPrice = items.reduce((acc, item) => acc + item.price * item.qty, 0); const discountRate = totalPrice >= 20000 ? 0.1 : totalPrice >= 10000 ? 0.05 : 0; const finalPrice = totalPrice * (1 - discountRate); const handleSubmit = async () => { dispatch({type: REDUCER_TYPE.SUBMIT}); try { await submitOrder(items, finalPrice); dispatch({type: REDUCER_TYPE.DONE}); } catch (e) { dispatch({type: REDUCER_TYPE.ERROR, message: e.message}); } }; }
